# Scratch: იგივეა რაც "თუ მაშინ" ბლოკი
ამინდი = input("როგორია ამინდი? (მზიანი/წვიმიანი): ")
if ამინდი == "მზიანი":
    print("გარეთ ვითამაშოთ!")
else:
    print("პროგრამირება ვისწავლოთ!")

# Scratch: იგივეა რაც "თუ მაშინ თუარადა თუ მაშინ" ბლოკი
საათი = int(input("რომელი საათია? (0-23): "))
if საათი < 10:
    print("დილა მშვიდობისა!")
elif საათი < 17:
    print("შუადღე მშვიდობისა!")
else:
    print("საღამო მშვიდობისა!")

